{"source": "<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Praxis AI — Operational Diagnostic Report</title>
<link href="https://fonts.googleapis.com/css2?family=DM+Serif+Display&family=DM+Sans:opsz,wght@9..40,300;9..40,400;9..40,500;9..40,600&family=DM+Mono:wght@400;500&display=swap" rel="stylesheet">
<style>
:root {
  --teal:#4bb4a5; --teal-light:#5ac3b4; --teal-dim:#e8f5f3; --teal-deep:#1e3c3c;
  --charcoal:#2d2d2d; --charcoal-mid:#4a4a4a; --charcoal-light:#7a7a7a;
  --rule:#e0e6e5; --page:#f7fafa; --white:#ffffff;
  --red:#c0392b; --red-dim:#fdf0ee;
  --amber:#d4820a; --amber-dim:#fdf6e8;
  --green:#27836a; --green-dim:#e8f5f1;
}
*{margin:0;padding:0;box-sizing:border-box;}
body{font-family:'DM Sans',sans-serif;background:#ffffff;color:var(--charcoal);font-size:13px;line-height:1.6;-webkit-print-color-adjust:exact;print-color-adjust:exact;}

/* ── CORE PAGE RULE ── */
.page{width:794px;height:1123px;overflow:hidden;margin:0 auto;background:var(--white);box-shadow:0 4px 40px rgba(0,0,0,0.15);position:relative;page-break-after:always;break-after:page;}
.page:last-child{page-break-after:avoid;break-after:avoid;}

/* COVER */
.cover{height:1123px;background:var(--charcoal);display:flex;flex-direction:column;position:relative;overflow:hidden;}
.cover-teal-bar{position:absolute;top:0;left:0;right:0;height:4px;background:linear-gradient(90deg,var(--teal),var(--teal-light));}
.cover-grid{position:absolute;inset:0;background-image:linear-gradient(rgba(75,180,165,0.06) 1px,transparent 1px),linear-gradient(90deg,rgba(75,180,165,0.06) 1px,transparent 1px);background-size:44px 44px;}
.cover-glow{position:absolute;top:-80px;right:-80px;width:400px;height:400px;border-radius:50%;background:radial-gradient(circle,rgba(75,180,165,0.15) 0%,transparent 65%);}
.cover-header{padding:40px 52px 0;display:flex;justify-content:space-between;align-items:flex-start;position:relative;z-index:2;}
.cover-logo img{height:110px;width:auto;}
.cover-confidential{font-family:'DM Mono',monospace;font-size:9px;letter-spacing:0.14em;text-transform:uppercase;color:rgba(255,255,255,0.5);text-align:right;line-height:1.9;padding-top:6px;border-top:1px solid rgba(75,180,165,0.4);}
.cover-body{flex:1;padding:24px 52px 0;position:relative;z-index:2;display:flex;flex-direction:column;}
.cover-eyebrow{font-family:'DM Mono',monospace;font-size:10px;letter-spacing:0.2em;text-transform:uppercase;color:var(--teal);margin-bottom:14px;}
.cover-headline{font-family:'DM Serif Display',serif;font-size:42px;line-height:1.1;color:#ffffff;margin-bottom:22px;max-width:560px;}
.cover-divider{width:44px;height:2px;background:var(--teal);margin-bottom:22px;}
.cover-meta-grid{display:grid;grid-template-columns:repeat(3,1fr);border:1px solid rgba(75,180,165,0.25);max-width:580px;margin-bottom:28px;}
.cover-meta-item{padding:13px 18px;border-right:1px solid rgba(75,180,165,0.2);border-bottom:1px solid rgba(75,180,165,0.2);}
.cover-meta-item:nth-child(3),.cover-meta-item:nth-child(6){border-right:none;}
.cover-meta-item:nth-child(4),.cover-meta-item:nth-child(5),.cover-meta-item:nth-child(6){border-bottom:none;}
.cover-meta-label{font-family:'DM Mono',monospace;font-size:9px;letter-spacing:0.14em;text-transform:uppercase;color:rgba(255,255,255,0.45);margin-bottom:4px;}
.cover-meta-value{font-size:13px;font-weight:500;color:#ffffff;}
.cover-chart-section{flex:1;display:flex;flex-direction:column;justify-content:center;padding-bottom:0;min-height:0;}
.cover-chart-header{display:flex;justify-content:space-between;align-items:center;margin-bottom:10px;}
.cover-chart-title{font-family:'DM Mono',monospace;font-size:11px;letter-spacing:0.16em;text-transform:uppercase;color:rgba(255,255,255,0.7);font-weight:500;}
.cover-chart-overall{font-family:'DM Serif Display',serif;font-size:26px;color:#ffffff;}
.cover-chart-overall span{font-family:'DM Mono',monospace;font-size:12px;color:rgba(255,255,255,0.55);margin-left:4px;}
.cover-chart-img{flex:1;display:flex;align-items:center;justify-content:center;width:100%;}
.cover-chart-img img{width:100%;height:auto;display:block;max-width:690px;}
.cover-footer{padding:20px 52px;border-top:1px solid rgba(75,180,165,0.15);display:flex;justify-content:space-between;align-items:center;position:relative;z-index:2;}
.cover-footer-text{font-family:'DM Mono',monospace;font-size:9px;color:rgba(255,255,255,0.35);letter-spacing:0.08em;}

/* INNER PAGES */
.inner-page{height:1123px;display:flex;flex-direction:column;padding:0 52px 0;border-top:1px solid var(--rule);position:relative;overflow:hidden;}
.inner-page::before{content:'';position:absolute;top:0;left:0;right:0;height:3px;background:linear-gradient(90deg,var(--teal),var(--teal-light));}
.page-header{display:flex;justify-content:space-between;align-items:center;padding:18px 0 14px;border-bottom:1px solid var(--rule);flex-shrink:0;}
.page-header-logo img{height:90px;width:auto;}
.page-header-right{font-family:'DM Mono',monospace;font-size:9px;color:var(--charcoal-light);letter-spacing:0.1em;text-align:right;line-height:1.8;text-transform:uppercase;}
.page-content{flex:1;overflow:hidden;display:flex;flex-direction:column;}
.report-footer{border-top:1px solid var(--rule);display:flex;justify-content:space-between;align-items:center;background:var(--page);flex-shrink:0;margin:0 -52px;padding:12px 52px;}
.footer-disclaimer{font-size:9px;color:var(--charcoal-light);max-width:500px;line-height:1.5;font-family:'DM Mono',monospace;}
.footer-page{font-family:'DM Mono',monospace;font-size:10px;color:var(--charcoal-light);flex-shrink:0;}

.section-eyebrow{font-family:'DM Mono',monospace;font-size:9px;letter-spacing:0.18em;text-transform:uppercase;color:var(--teal);margin-bottom:6px;flex-shrink:0;}
.section-title{font-family:'DM Serif Display',serif;font-size:24px;color:var(--charcoal);margin-bottom:14px;line-height:1.2;flex-shrink:0;}

/* EXEC SUMMARY */
.exec-summary{background:var(--charcoal);padding:20px 26px;margin-bottom:18px;position:relative;flex-shrink:0;}
.exec-summary::before{content:'';position:absolute;left:0;top:0;bottom:0;width:3px;background:var(--teal);}
.exec-summary p{font-size:12.5px;line-height:1.75;color:#e8e8e8;}

/* SCORECARD */
.scorecard{margin-bottom:18px;flex-shrink:0;}
.scorecard-row{display:flex;align-items:center;gap:12px;padding:8px 0;border-bottom:1px solid var(--rule);}
.scorecard-row:last-child{border-bottom:none;}
.scorecard-dim{width:185px;font-size:11.5px;font-weight:500;color:var(--charcoal);flex-shrink:0;}
.scorecard-bar-track{flex:1;height:5px;background:var(--teal-dim);border-radius:3px;overflow:visible;position:relative;}
.scorecard-bar-track::after{content:'';position:absolute;left:60%;top:-3px;width:2px;height:11px;background:rgba(212,130,10,0.75);border-radius:1px;}
.scorecard-bar-fill{height:100%;border-radius:3px;}
.scorecard-score{width:26px;font-family:'DM Mono',monospace;font-size:12px;font-weight:500;text-align:right;color:var(--charcoal);flex-shrink:0;}
.scorecard-tag{width:230px;font-size:9px;font-family:'DM Mono',monospace;letter-spacing:0.04em;flex-shrink:0;padding:3px 7px;border-radius:2px;}

/* DISCLAIMER */
.disclaimer-block{background:#1a1a1a;border:2px solid var(--amber);padding:18px 22px;flex-shrink:0;}
.disclaimer-icon-row{display:flex;align-items:center;gap:10px;margin-bottom:10px;}
.disclaimer-icon{width:24px;height:24px;background:var(--amber);color:#1a1a1a;font-size:13px;font-weight:700;display:flex;align-items:center;justify-content:center;flex-shrink:0;}
.disclaimer-heading{font-family:'DM Mono',monospace;font-size:10px;letter-spacing:0.13em;text-transform:uppercase;color:var(--amber);}
.disclaimer-text{font-size:10.5px;line-height:1.65;color:#d8d8d8;}
.disclaimer-text strong{color:#ffffff;font-weight:600;}
.disclaimer-text em{color:rgba(255,255,255,0.8);font-style:italic;}

/* DIMENSION PAGES */
.dim-page-header{display:flex;justify-content:space-between;align-items:flex-end;margin-bottom:12px;padding-bottom:12px;border-bottom:2px solid var(--charcoal);flex-shrink:0;}
.dim-number{font-family:'DM Mono',monospace;font-size:11px;letter-spacing:0.2em;text-transform:uppercase;color:var(--teal);margin-bottom:4px;font-weight:500;}
.dim-title{font-family:'DM Serif Display',serif;font-size:26px;color:var(--charcoal);line-height:1.1;}
.dim-score-badge{display:flex;align-items:baseline;gap:6px;flex-shrink:0;}
.dim-score-num{font-family:'DM Serif Display',serif;font-size:48px;color:var(--teal);line-height:1;font-weight:700;}
.dim-score-denom{font-family:'DM Mono',monospace;font-size:13px;color:var(--charcoal-light);font-weight:500;}
.dim-score-status{font-family:'DM Mono',monospace;font-size:11px;font-weight:600;letter-spacing:0.06em;text-transform:uppercase;padding:4px 10px;border-radius:3px;align-self:center;}

.dim-findings{margin-bottom:12px;flex-shrink:0;}
.dim-findings p{font-size:12.5px;line-height:1.72;color:var(--charcoal-mid);margin-bottom:10px;}
.dim-findings p:last-child{margin-bottom:0;}

.callout{margin:0 0 8px 0;padding:11px 14px;border-left:3px solid var(--teal);background:var(--teal-dim);flex-shrink:0;}
.callout:last-of-type{margin-bottom:0;}
.callout-label{font-family:'DM Mono',monospace;font-size:9px;letter-spacing:0.14em;text-transform:uppercase;color:var(--teal-deep);margin-bottom:4px;}
.callout-body{font-size:12px;line-height:1.6;color:var(--charcoal);}
.callouts-block{margin-bottom:12px;flex-shrink:0;}

.metric-row{display:grid;grid-template-columns:repeat(3,1fr);gap:8px;margin-bottom:12px;flex-shrink:0;}
.metric-card{padding:12px 11px;background:var(--page);border:1px solid var(--rule);border-top:2px solid var(--teal);}
.metric-num{font-family:'DM Serif Display',serif;font-size:20px;color:var(--teal-deep);line-height:1;margin-bottom:3px;}
.metric-label{font-size:10.5px;font-weight:600;color:var(--charcoal);margin-bottom:2px;}
.metric-note{font-size:9.5px;color:var(--charcoal-light);line-height:1.4;}

/* MATURITY LADDER */
.maturity-block{margin-bottom:8px;flex-shrink:0;background:var(--page);border:1px solid var(--rule);border-top:2px solid var(--charcoal);padding:11px 14px;}
.maturity-label{font-family:'DM Mono',monospace;font-size:9px;letter-spacing:0.16em;text-transform:uppercase;color:var(--charcoal-light);margin-bottom:7px;}
.maturity-track{display:flex;gap:3px;align-items:stretch;height:26px;}
.maturity-seg{flex:1;display:flex;align-items:center;justify-content:center;font-family:'DM Mono',monospace;font-size:9px;font-weight:500;border-radius:2px;position:relative;}
.maturity-seg.active{outline:2px solid var(--charcoal);outline-offset:1px;}
.maturity-names{display:flex;gap:3px;margin-top:16px;}
.maturity-name{flex:2;font-size:8.5px;color:var(--charcoal-light);text-align:center;}

/* WHAT GOOD LOOKS LIKE */
.wgl-block{background:var(--teal-dim);border:1px solid rgba(75,180,165,0.35);border-top:2px solid var(--teal);padding:11px 14px;flex-shrink:0;margin-bottom:8px;}
.wgl-label{font-family:'DM Mono',monospace;font-size:9px;letter-spacing:0.16em;text-transform:uppercase;color:var(--teal-deep);margin-bottom:8px;}
.wgl-items{display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;}
.wgl-item{display:flex;gap:7px;align-items:flex-start;}
.wgl-tick{width:14px;height:14px;border-radius:50%;background:#ffffff;border:1.5px solid var(--teal);display:flex;align-items:center;justify-content:center;flex-shrink:0;margin-top:1px;}
.wgl-tick svg{width:8px;height:8px;}
.wgl-text{font-size:10.5px;line-height:1.5;color:var(--charcoal-mid);}

/* ROI STRIP */
.roi-block{background:var(--charcoal);border-top:2px solid var(--amber);padding:10px 14px;flex-shrink:0;display:flex;align-items:stretch;gap:0;}
.roi-label-col{display:flex;flex-direction:column;justify-content:center;padding-right:14px;border-right:1px solid rgba(255,255,255,0.12);flex-shrink:0;min-width:90px;}
.roi-eyebrow{font-family:'DM Mono',monospace;font-size:8px;letter-spacing:0.16em;text-transform:uppercase;color:var(--amber);margin-bottom:2px;}
.roi-sublabel{font-size:8.5px;color:rgba(255,255,255,0.4);font-style:italic;}
.roi-items{display:flex;flex:1;gap:0;}
.roi-item{flex:1;padding:0 14px;border-right:1px solid rgba(255,255,255,0.1);display:flex;flex-direction:column;justify-content:center;}
.roi-item:last-child{border-right:none;}
.roi-type{font-family:'DM Mono',monospace;font-size:8px;letter-spacing:0.1em;text-transform:uppercase;color:rgba(255,255,255,0.45);margin-bottom:3px;}
.roi-value{font-family:'DM Serif Display',serif;font-size:17px;color:var(--amber);line-height:1;margin-bottom:2px;}
.roi-desc{font-size:9.5px;color:rgba(255,255,255,0.6);line-height:1.4;}

/* ACTIONS */
.actions-section{flex-shrink:0;}
.action-item{display:flex;gap:14px;padding:10px 0;border-bottom:1px solid var(--rule);}
.action-item:last-child{border-bottom:none;}
.action-num{font-family:'DM Serif Display',serif;font-size:24px;color:var(--teal);line-height:1;flex-shrink:0;width:26px;padding-top:2px;}
.action-title{font-size:12.5px;font-weight:600;color:var(--charcoal);margin-bottom:4px;}
.action-body{font-size:11.5px;line-height:1.65;color:var(--charcoal-mid);}

/* UPSELL */
.upsell-section{background:var(--charcoal);padding:22px 28px;margin-top:16px;position:relative;overflow:hidden;flex-shrink:0;}
.upsell-section::before{content:'';position:absolute;top:0;left:0;right:0;height:3px;background:linear-gradient(90deg,var(--teal),var(--teal-light));}
.upsell-bg{position:absolute;inset:0;background-image:linear-gradient(rgba(75,180,165,0.05) 1px,transparent 1px),linear-gradient(90deg,rgba(75,180,165,0.05) 1px,transparent 1px);background-size:28px 28px;}
.upsell-eyebrow{font-family:'DM Mono',monospace;font-size:9px;letter-spacing:0.18em;text-transform:uppercase;color:var(--teal);margin-bottom:4px;position:relative;}
.upsell-title{font-family:'DM Serif Display',serif;font-size:19px;color:#ffffff;margin-bottom:5px;position:relative;}
.upsell-intro{font-size:12px;color:#cccccc;margin-bottom:14px;max-width:560px;position:relative;line-height:1.6;}
.upsell-cards{display:grid;grid-template-columns:1fr 1fr;gap:12px;position:relative;}
.upsell-card{background:rgba(75,180,165,0.09);border:1px solid rgba(75,180,165,0.25);padding:15px;border-top:2px solid var(--teal);}
.upsell-card-score{font-family:'DM Mono',monospace;font-size:9px;color:rgba(255,255,255,0.6);letter-spacing:0.08em;margin-bottom:6px;}
.upsell-card-title{font-family:'DM Serif Display',serif;font-size:14px;color:#ffffff;margin-bottom:7px;line-height:1.25;}
.upsell-card-desc{font-size:11.5px;line-height:1.6;color:#c0c0c0;margin-bottom:12px;}
.upsell-price{display:flex;align-items:baseline;gap:4px;border-top:1px solid rgba(75,180,165,0.2);padding-top:10px;}
.upsell-price-num{font-family:'DM Serif Display',serif;font-size:20px;color:var(--teal-light);}
.upsell-price-label{font-size:11px;color:rgba(255,255,255,0.5);}
</style>
</head>
<body>

<!-- ══ PAGE 1: COVER ══ -->
<div class="page">
<div class="cover">
  <div class="cover-teal-bar"></div>
  <div class="cover-grid"></div>
  <div class="cover-glow"></div>
  <div class="cover-header">
    <div class="cover-logo"><img src="https://files.manuscdn.com/user_upload_by_module/session_file/310419663030227401/XziUQERRfNIlKcWj.png" alt="Praxis AI"></div>
    <div class="cover-confidential">Operational Diagnostic Report<br>Confidential — Prepared for recipient only<br>{{4.report_date}}</div>
  </div>
  <div class="cover-body">
    <div class="cover-eyebrow">Praxis AI Operational Intelligence Report</div>
    <div class="cover-headline">{{4.business_name}}</div>
    <div class="cover-divider"></div>
    <div class="cover-meta-grid">
      <div class="cover-meta-item"><div class="cover-meta-label">Business</div><div class="cover-meta-value">{{4.business_name}}</div></div>
      <div class="cover-meta-item"><div class="cover-meta-label">Industry</div><div class="cover-meta-value">{{4.industry}}</div></div>
      <div class="cover-meta-item"><div class="cover-meta-label">Report Date</div><div class="cover-meta-value">{{4.report_date}}</div></div>
      <div class="cover-meta-item"><div class="cover-meta-label">Revenue Band</div><div class="cover-meta-value">{{4.revenue_band}}</div></div>
      <div class="cover-meta-item"><div class="cover-meta-label">Staff</div><div class="cover-meta-value">{{4.staff_count}}</div></div>
      <div class="cover-meta-item"><div class="cover-meta-label">Years Operating</div><div class="cover-meta-value">{{4.years_operating}}</div></div>
    </div>
    <div class="cover-chart-section">
      <div class="cover-chart-header">
        <div class="cover-chart-title">Six-Dimension Score Profile</div>
        <div class="cover-chart-overall">{{4.overall_score}} <span>/ 10 Overall</span></div>
      </div>
      <div class="cover-chart-img">
<div class="cover-chart-svg-wrap">
<svg id="radar" viewBox="0 0 690 340" xmlns="http://www.w3.org/2000/svg" style="width:690px;height:340px;display:block;">
  <defs><style>
