  <text id="slabel5" class="rs" x="0" y="0"></text>
  <text class="rl" x="345.0" y="18.0" text-anchor="middle"><tspan x="345.0" dy="0">Process &amp;</tspan><tspan x="345.0" dy="13">Workflow</tspan></text>
