    parseFloat("{{4.dim6_score}}")||0
  ];
  var pts=[];
  for(var i=0;i<6;i++){
    var a=Math.PI*(-0.5+i*2/6);
    var r=(scores[i]/10)*maxR;
    var x=cx+r*Math.cos(a);
    var y=cy+r*Math.sin(a);
    pts.push(x.toFixed(1)+","+y.toFixed(1));
    var d=document.getElementById("dot"+i);
    d.setAttribute("cx",x.toFixed(1));
    d.setAttribute("cy",y.toFixed(1));
    var lr=r+16;
    var sl=document.getElementById("slabel"+i);
    sl.setAttribute("x",(cx+lr*Math.cos(a)).toFixed(1));
    sl.setAttribute("y",(cy+lr*Math.sin(a)+4).toFixed(1));
    sl.setAttribute("text-anchor","middle");
    sl.textContent=scores[i];
  }
  document.getElementById("score-poly").setAttribute("points",pts.join(" "));
})();
</script>
